const items = $input.all();

if (items.length === 0 || !items[0].json.ID_Pedido) {
  return [{ json: { Mensaje: 'No se encontraron pedidos activos para este cliente.' } }];
}

const estadosValidos = ['activo', 'modificado'];
const pedidos = items.filter(i =>
  i.json.ID_Pedido && estadosValidos.includes((i.json.Estado || '').toLowerCase())
);

if (pedidos.length === 0) {
  return [{ json: { Mensaje: 'No se encontraron pedidos activos para este cliente.' } }];
}

pedidos.sort((a, b) => new Date(b.json.Fecha_Hora) - new Date(a.json.Fecha_Hora));

if (pedidos.length === 1) {
  const pedido = pedidos[0].json;
  return [{
    json: {
      Mensaje: `Pedido encontrado. ID: ${pedido.ID_Pedido}. Fecha: ${pedido.Fecha_Hora}. Productos: ${pedido.Productos}. Total: ${pedido.Total_EUR}€`,
      id_pedido: pedido.ID_Pedido,
      fecha: pedido.Fecha_Hora,
      productos: pedido.Productos,
      total: pedido.Total_EUR,
      estado: pedido.Estado,
      total_pedidos: 1
    }
  }];
}

// Multiples pedidos activos
const lineas = pedidos.map((p, i) => {
  const ped = p.json;
  return `Pedido ${i + 1}: ${ped.Productos} - Total: ${ped.Total_EUR}€ [ID: ${ped.ID_Pedido}]`;
});

return [{
  json: {
    Mensaje: `El cliente tiene ${pedidos.length} pedidos activos:\n${lineas.join('\n')}`,
    total_pedidos: pedidos.length,
    pedidos: pedidos.map(p => ({
      id_pedido: p.json.ID_Pedido,
      fecha: p.json.Fecha_Hora,
      productos: p.json.Productos,
      total: p.json.Total_EUR,
      estado: p.json.Estado
    }))
  }
}];

